  1→package org.wordpress.android.ui.stats.refresh.lists
  2→
  3→import org.wordpress.android.R
  4→import org.wordpress.android.fluxc.store.StatsStore.InsightType
  5→import org.wordpress.android.fluxc.store.StatsStore.PostDetailType
  6→import org.wordpress.android.fluxc.store.StatsStore.StatsType
  7→import org.wordpress.android.fluxc.store.StatsStore.TimeStatsType
  8→import org.wordpress.android.ui.stats.refresh.lists.StatsListViewModel.UiModel
  9→import org.wordpress.android.ui.stats.refresh.lists.sections.BaseStatsUseCase.UseCaseModel
 10→import org.wordpress.android.ui.stats.refresh.lists.sections.BaseStatsUseCase.UseCaseModel.UseCaseState.EMPTY
 11→import org.wordpress.android.ui.stats.refresh.lists.sections.BaseStatsUseCase.UseCaseModel.UseCaseState.ERROR
 12→import org.wordpress.android.ui.stats.refresh.lists.sections.BaseStatsUseCase.UseCaseModel.UseCaseState.LOADING
 13→import org.wordpress.android.ui.stats.refresh.lists.sections.BaseStatsUseCase.UseCaseModel.UseCaseState.SUCCESS
 14→import org.wordpress.android.util.NetworkUtilsWrapper
 15→import javax.inject.Inject
 16→
 17→class UiModelMapper
 18→@Inject constructor(private val networkUtilsWrapper: NetworkUtilsWrapper) {
 19→    fun mapInsights(useCaseModels: List<UseCaseModel>, showError: (Int) -> Unit): UiModel {
 20→        val insightUseCaseModels = useCaseModels.filter { it.type is InsightType }
 21→        if (insightUseCaseModels.isNotEmpty()) {
 22→            val allFailing = allFailing(insightUseCaseModels)
 23→            val allFailingWithoutData = allFailingWithoutData(insightUseCaseModels)
 24→            return if (!allFailing && !allFailingWithoutData) {
 25→                val data = useCaseModels.map { useCaseModel ->
 26→                    when (useCaseModel.state) {
 27→                        SUCCESS -> StatsBlock.Success(useCaseModel.type, useCaseModel.data ?: listOf())
 28→                        ERROR -> StatsBlock.Error(
 29→                            useCaseModel.type,
 30→                            useCaseModel.stateData ?: useCaseModel.data ?: listOf()
 31→                        )
 32→                        LOADING -> StatsBlock.Loading(
 33→                            useCaseModel.type,
 34→                            useCaseModel.stateData ?: useCaseModel.data ?: listOf()
 35→                        )
 36→                        EMPTY -> StatsBlock.EmptyBlock(
 37→                            useCaseModel.type,
 38→                            useCaseModel.stateData ?: useCaseModel.data ?: listOf()
 39→                        )
 40→                    }
 41→                }
 42→                UiModel.Success(data)
 43→            } else if (!allFailingWithoutData) {
 44→                showError(getErrorMessage())
 45→                getUiModelForAllFailingWithoutData(useCaseModels)
 46→            } else {
 47→                UiModel.Error(getErrorMessage())
 48→            }
 49→        } else {
 50→            return UiModel.Empty(
 51→                R.string.stats_empty_insights_title,
 52→                R.string.stats_insights_management_title,
 53→                R.drawable.img_illustration_insights_94dp,
 54→                true
 55→            )
 56→        }
 57→    }
 58→
 59→    fun mapTimeStats(
 60→        useCaseModels: List<UseCaseModel>,
 61→        showError: (Int) -> Unit
 62→    ): UiModel {
 63→        return mapStatsWithOverview(TimeStatsType.OVERVIEW, useCaseModels, showError)
 64→    }
 65→
 66→    fun mapSubscribers(useCaseModels: List<UseCaseModel>, showError: (Int) -> Unit): UiModel {
 67→        val allFailing = useCaseModels.isNotEmpty() && allFailing(useCaseModels)
 68→        val allFailingWithoutData = allFailingWithoutData(useCaseModels)
 69→        return if (useCaseModels.isEmpty()) {
 70→            UiModel.Empty(R.string.loading)
 71→        } else if (!allFailing && !allFailingWithoutData) {
 72→            val data = useCaseModels.mapNotNull { useCaseModel ->
 73→                when (useCaseModel.state) {
 74→                    LOADING -> useCaseModel.stateData?.let {
 75→                        StatsBlock.Loading(useCaseModel.type, useCaseModel.stateData)
 76→                    }
 77→
 78→                    SUCCESS -> StatsBlock.Success(useCaseModel.type, useCaseModel.data ?: listOf())
 79→                    ERROR -> useCaseModel.stateData?.let {
 80→                        StatsBlock.Error(useCaseModel.type, useCaseModel.stateData)
 81→                    }
 82→
 83→                    EMPTY -> useCaseModel.stateData?.let {
 84→                        StatsBlock.EmptyBlock(useCaseModel.type, useCaseModel.stateData)
 85→                    }
 86→                }
 87→            }
 88→            UiModel.Success(data)
 89→        } else if (!allFailingWithoutData) {
 90→            showError(getErrorMessage())
 91→            getUiModelForAllFailingWithoutData(useCaseModels)
 92→        } else {
 93→            UiModel.Error(getErrorMessage())
 94→        }
 95→    }
 96→
 97→    fun mapDetailStats(
 98→        useCaseModels: List<UseCaseModel>,
 99→        showError: (Int) -> Unit
100→    ): UiModel {
101→        return mapStatsWithOverview(PostDetailType.POST_OVERVIEW, useCaseModels, showError)
102→    }
103→
104→    @Suppress("CyclomaticComplexMethod")
105→    private fun mapStatsWithOverview(
106→        overViewType: StatsType,
107→        useCaseModels: List<UseCaseModel>,
108→        showError: (Int) -> Unit
109→    ): UiModel {
110→        val allFailing = useCaseModels.isNotEmpty() && allFailing(useCaseModels)
111→        val overviewIsFailing = useCaseModels.any { it.type == overViewType && it.state == ERROR }
112→        val overviewHasData = useCaseModels.any { it.type == overViewType && it.data != null }
113→        return if (!allFailing && (overviewHasData || !overviewIsFailing)) {
114→            if (useCaseModels.isNotEmpty()) {
115→                UiModel.Success(
116→                    useCaseModels.mapNotNull { useCaseModel ->
117→                        when {
118→                            useCaseModel.state == LOADING -> useCaseModel.stateData?.let {
119→                                StatsBlock.Loading(useCaseModel.type, useCaseModel.stateData)
120→                            }
121→
122→                            useCaseModel.type == overViewType && useCaseModel.data != null -> StatsBlock.Success(
123→                                useCaseModel.type,
124→                                useCaseModel.data
125→                            )
126→
127→                            useCaseModel.state == SUCCESS -> StatsBlock.Success(
128→                                useCaseModel.type,
129→                                useCaseModel.data ?: listOf()
130→                            )
131→
132→                            useCaseModel.state == ERROR -> useCaseModel.stateData?.let {
133→                                StatsBlock.Error(useCaseModel.type, useCaseModel.stateData)
134→                            }
135→
136→                            useCaseModel.state == EMPTY -> useCaseModel.stateData?.let {
137→                                StatsBlock.EmptyBlock(useCaseModel.type, useCaseModel.stateData)
138→                            }
139→
140→                            else -> null
141→                        }
142→                    }
143→                )
144→            } else {
145→                UiModel.Empty(R.string.loading)
146→            }
147→        } else if (overviewHasData) {
148→            showError(getErrorMessage())
149→            UiModel.Success(
150→                useCaseModels.mapNotNull { useCaseModel ->
151→                    if ((useCaseModel.type == overViewType) && useCaseModel.data != null) {
152→                        StatsBlock.Success(useCaseModel.type, useCaseModel.data)
153→                    } else {
154→                        useCaseModel.stateData?.let {
155→                            StatsBlock.Error(
156→                                useCaseModel.type,
157→                                useCaseModel.stateData
158→                            )
159→                        }
160→                    }
161→                }
162→            )
163→        } else {
164→            UiModel.Error(getErrorMessage())
165→        }
166→    }
167→
168→    private fun allFailing(useCaseModels: List<UseCaseModel>) = useCaseModels.fold(true) { acc, useCaseModel ->
169→        acc && useCaseModel.state == ERROR
170→    }
171→
172→    private fun allFailingWithoutData(useCaseModels: List<UseCaseModel>) =
173→        useCaseModels.fold(true) { acc, useCaseModel ->
174→            acc && useCaseModel.state == ERROR && useCaseModel.data == null
175→        }
176→
177→    private fun getUiModelForAllFailingWithoutData(useCaseModels: List<UseCaseModel>) = UiModel.Success(
178→        useCaseModels.map { useCaseModel ->
179→            StatsBlock.Error(
180→                useCaseModel.type,
181→                useCaseModel.data ?: useCaseModel.stateData ?: listOf()
182→            )
183→        }
184→    )
185→
186→    private fun getErrorMessage(): Int {
187→        return if (networkUtilsWrapper.isNetworkAvailable()) {
188→            R.string.stats_loading_error
189→        } else {
190→            R.string.no_network_title
191→        }
192→    }
193→}
