121→        Bundle extras = getIntent().getExtras();
122→        if (extras != null) {
123→            if (extras.containsKey(EXTRA_POST_LOCAL_ID)) {
124→                int localPostId = extras.getInt(EXTRA_POST_LOCAL_ID);
125→                PostModel post = mPostStore.getPostByLocalPostId(localPostId);
126→                if (post != null) {
127→                    for (Long categoryId : post.getCategoryIdList()) {
128→                        mSelectedCategories.add(categoryId);
129→                    }
130→                }
131→            }
132→        }
133→
134→        // swipe to refresh setup
135→        mSwipeToRefreshHelper = buildSwipeToRefreshHelper(
136→                (CustomSwipeRefreshLayout) findViewById(R.id.ptr_layout),
137→                new RefreshListener() {
138→                    @Override
139→                    public void onRefreshStarted() {
140→                        if (!NetworkUtils.checkConnection(getBaseContext())) {
141→                            mSwipeToRefreshHelper.setRefreshing(false);
142→                            return;
143→                        }
144→                        refreshCategories();
145→                    }
146→                }
147→        );
148→
149→        populateCategoryList();
150→
151→        if (NetworkUtils.isNetworkAvailable(this)) {
152→            mEmptyView.setText(R.string.empty_list_default);
153→            if (isCategoryListEmpty()) {
154→                refreshCategories();
155→            }
156→        } else {
157→            mEmptyView.setText(R.string.no_network_title);
158→        }
