254→    private void updateSelectedCategoryList() {
255→        SparseBooleanArray selectedItems = mListView.getCheckedItemPositions();
256→        for (int i = 0; i < selectedItems.size(); i++) {
257→            if (selectedItems.keyAt(i) >= mCategoryLevels.size()) {
258→                continue;
259→            }
260→
261→            long categoryRemoteId = mCategoryLevels.get(selectedItems.keyAt(i)).getCategoryId();
262→            if (selectedItems.get(selectedItems.keyAt(i))) {
263→                mSelectedCategories.add(categoryRemoteId);
264→            } else {
265→                mSelectedCategories.remove(categoryRemoteId);
266→            }
267→        }
268→    }
