267→    private void showQuickStartFocusPoint() {
268→        // we are waiting for RecyclerView to populate itself with views and then grab the first one when it's ready
269→        mRecycler.getViewTreeObserver().addOnGlobalLayoutListener(new ViewTreeObserver.OnGlobalLayoutListener() {
270→            @Override public void onGlobalLayout() {
271→                RecyclerView.ViewHolder holder = mRecycler.findViewHolderForAdapterPosition(0);
272→                if (holder != null) {
273→                    final View quickStartTarget = holder.itemView;
274→
275→                    quickStartTarget.post(new Runnable() {
276→                        @Override public void run() {
277→                            if (getView() == null) {
278→                                return;
279→                            }
280→                            ViewGroup focusPointContainer = getView().findViewById(R.id.publicize_scroll_view_child);
281→                            int focusPointSize =
282→                                    getResources().getDimensionPixelOffset(R.dimen.quick_start_focus_point_size);
283→
284→                            int verticalOffset = (((quickStartTarget.getHeight()) - focusPointSize) / 2);
285→
286→                            QuickStartUtils.addQuickStartFocusPointAboveTheView(focusPointContainer, quickStartTarget,
287→                                    0, verticalOffset);
288→                        }
289→                    });
290→                    mRecycler.getViewTreeObserver().removeOnGlobalLayoutListener(this);
291→                }
292→            }
293→        });
294→    }
