298→                requireContext(),
299→                R.string.quick_start_dialog_enable_sharing_message_short_connections
300→        );
301→        new Handler().postDelayed(() -> mSnackbarSequencer.enqueue(
302→                new SnackbarItem(new Info(mRecycler, new UiStringText(title), Snackbar.LENGTH_LONG))
303→        ), 500L);
304→    }
