 72→    @Override
 73→    public void onCreate(@Nullable Bundle savedInstanceState) {
 74→        super.onCreate(savedInstanceState);
 75→        ((WordPress) getApplication()).component().inject(this);
 76→
 77→        OnBackPressedCallback callback = new OnBackPressedCallback(true) {
 78→            @Override
 79→            public void handleOnBackPressed() {
 80→                saveAndFinish();
 81→                CompatExtensionsKt.onBackPressedCompat(getOnBackPressedDispatcher(), this);
 82→            }
 83→        };
 84→        getOnBackPressedDispatcher().addCallback(this, callback);
 85→
 86→        mDispatcher.register(this);
 87→
 88→        if (savedInstanceState == null) {
 89→            mSite = (SiteModel) getIntent().getSerializableExtra(WordPress.SITE);
 90→        } else {
 91→            mSite = (SiteModel) savedInstanceState.getSerializable(WordPress.SITE);
 92→        }
 93→        if (mSite == null) {
 94→            ToastUtils.showToast(this, R.string.blog_not_found, ToastUtils.Duration.SHORT);
 95→            finish();
 96→            return;
 97→        }
 98→
 99→        setContentView(R.layout.select_categories);
100→
101→        Toolbar toolbar = findViewById(R.id.toolbar_main);
102→        setSupportActionBar(toolbar);
103→        ActionBar actionBar = getSupportActionBar();
104→        if (actionBar != null) {
105→            actionBar.setHomeButtonEnabled(true);
106→            actionBar.setDisplayHomeAsUpEnabled(true);
107→        }
108→
109→        setTitle(getResources().getString(R.string.select_categories));
110→
111→        mListView = (ListView) findViewById(android.R.id.list);
112→        mListScrollPositionManager = new ListScrollPositionManager(mListView, false);
