247→    private void refreshCategories() {
248→        mSwipeToRefreshHelper.setRefreshing(true);
249→        mListScrollPositionManager.saveScrollOffset();
250→        updateSelectedCategoryList();
251→        mDispatcher.dispatch(TaxonomyActionBuilder.newFetchCategoriesAction(mSite));
